package arch.day39;

public class Day39Basic {
    static class Bean {
        boolean inited;
        void init() { inited = true; }
        String status() { return inited ? "ready" : "not-ready"; }
    }

    public static void main(String[] args) {
        Bean b = new Bean();
        System.out.println(b.status());
        b.init();
        System.out.println(b.status());
    }
}

